document.addEventListener("DOMContentLoaded",(function(){if(document.body.classList.contains("elementor-editor-active"))return;const e=document.querySelector(".hero-banner-one");if(!e)return;gsap.registerPlugin(ScrollTrigger);const t=t=>e.querySelectorAll(t);gsap.set(t(".hero-banner-one-bg-reveal"),{scaleX:1}),gsap.set(t(".v-line"),{y:80,opacity:0}),gsap.set(t(".h-line"),{x:-120,opacity:0}),gsap.set(t(".hero-banner-one-thumbs img"),{y:20,opacity:0}),gsap.set(t(".hero-banner-one-right"),{y:30,opacity:0}),gsap.set(t(".hero-banner-one-desc"),{y:30,opacity:0}),gsap.set(t(".hero-banner-one-title"),{y:40,opacity:0});const o=gsap.timeline({scrollTrigger:{trigger:e,start:"top 80%",once:!0}});o.to(t(".hero-banner-one-bg-reveal"),{scaleX:0,duration:1.1,ease:"power4.inOut"}),o.to(t(".h-line"),{x:0,opacity:1,duration:.4},"-=0.6"),o.to(t(".v-line"),{y:0,opacity:1,duration:.4,stagger:.12},"-=0.4"),o.to(t(".hero-banner-one-thumbs img"),{y:0,opacity:1,duration:.3,stagger:.08},"-=0.3"),o.to(t(".hero-banner-one-right"),{y:0,opacity:1,duration:.45},"-=0.2"),o.to(t(".hero-banner-one-desc"),{y:0,opacity:1,duration:.45},"-=0.2"),o.to(t(".hero-banner-one-title"),{y:0,opacity:1,duration:.6,ease:"power3.out"},"-=0.25")}));